import{_ as e,o,c as d,a0 as a}from"./chunks/framework.B3sz4m_N.js";const m=JSON.parse('{"title":"Roadmap","description":"Phased plan from P0 security fixes through native migration and optional plugin extraction.","frontmatter":{"title":"Roadmap","description":"Phased plan from P0 security fixes through native migration and optional plugin extraction."},"headers":[],"relativePath":"reports/theme-only-audit-2/08-roadmap.md","filePath":"reports/theme-only-audit-2/08-roadmap.md"}'),r={name:"reports/theme-only-audit-2/08-roadmap.md"};function i(n,t,s,l,c,h){return o(),d("div",null,[...t[0]||(t[0]=[a(`<h1 id="_08-—-roadmap" tabindex="-1">08 — Roadmap <a class="header-anchor" href="#_08-—-roadmap" aria-label="Permalink to &quot;08 — Roadmap&quot;">​</a></h1><p>This document sequences every finding from documents <a href="./reports/theme-only-audit-2/00-summary.html">01–07</a> into an executable plan. Each phase declares its goal, scope, dependencies on earlier phases, effort estimate, and exit criteria.</p><p>Numbers are engineer-days on a mid-senior WordPress developer familiar with the codebase. <strong>Multiply by 1.5–2× for calendar time</strong> to account for review cycles, QA, scheduling, and context switching.</p><h2 id="contents" tabindex="-1">Contents <a class="header-anchor" href="#contents" aria-label="Permalink to &quot;Contents&quot;">​</a></h2><ul><li><a href="#phase-0--security-quick-wins-p0">Phase 0 — Security quick wins (P0)</a></li><li><a href="#phase-1--correctness-and-hygiene-quick-wins-p1">Phase 1 — Correctness and hygiene quick wins (P1)</a></li><li><a href="#phase-2--performance-wins-independent-of-migration">Phase 2 — Performance wins independent of migration</a></li><li><a href="#phase-25--hookability-pass">Phase 2.5 — Hookability pass</a></li><li><a href="#phase-3--block-kit-and-representative-native-block">Phase 3 — Block-kit and representative native block</a></li><li><a href="#phase-4--block-by-block-migration">Phase 4 — Block-by-block migration</a></li><li><a href="#phase-5--acf-removal--data-migration">Phase 5 — ACF removal + data migration</a></li><li><a href="#phase-6--dependency-removals">Phase 6 — Dependency removals</a></li><li><a href="#phase-7--plugin-extraction">Phase 7 — Plugin extraction</a></li><li><a href="#phase-8--parent-theme-evaluation-optional">Phase 8 — Parent-theme evaluation (optional)</a></li><li><a href="#total-effort">Total effort</a></li><li><a href="#dependencies-graph">Dependencies graph</a></li><li><a href="#recommended-order-of-client-rollout">Recommended order of client rollout</a></li></ul><h2 id="phase-0-—-security-quick-wins-p0" tabindex="-1">Phase 0 — Security quick wins (P0) <a class="header-anchor" href="#phase-0-—-security-quick-wins-p0" aria-label="Permalink to &quot;Phase 0 — Security quick wins (P0)&quot;">​</a></h2><p><strong>Goal</strong>: Eliminate the two P0 security findings before anything else happens.</p><table tabindex="0"><thead><tr><th>Task</th><th>Ref</th><th>Effort</th></tr></thead><tbody><tr><td>Fix SVG upload — add sanitizer or remove mime whitelist</td><td><a href="./reports/theme-only-audit-2/04-security.html#svg-uploads">04 SEC-SVG-01</a></td><td>0.5d</td></tr><tr><td>Fix site-scripts injection — replace free-form paste or gate + escape everything</td><td><a href="./reports/theme-only-audit-2/04-security.html#site-scripts-injection-from-theme-options">04 SEC-SITESCRIPTS-01</a></td><td>1.5d</td></tr><tr><td>Fix <code>single.php</code> missing <code>get_header/get_footer</code></td><td><a href="./reports/theme-only-audit-2/01-conventions-and-structure.html#template-hierarchy">01 TPL-01</a></td><td>0.25d</td></tr></tbody></table><p><strong>Total</strong>: 2.25 days.</p><p><strong>Exit criteria</strong>: Security findings marked P0 are closed. No behavioural regressions.</p><p><strong>Can ship independently</strong>: Yes. Deploy to all live sites immediately.</p><h2 id="phase-1-—-correctness-and-hygiene-quick-wins-p1" tabindex="-1">Phase 1 — Correctness and hygiene quick wins (P1) <a class="header-anchor" href="#phase-1-—-correctness-and-hygiene-quick-wins-p1" aria-label="Permalink to &quot;Phase 1 — Correctness and hygiene quick wins (P1)&quot;">​</a></h2><p><strong>Goal</strong>: Fix functional bugs and structural issues that don&#39;t require migration.</p><table tabindex="0"><thead><tr><th>Task</th><th>Ref</th><th>Effort</th></tr></thead><tbody><tr><td>Remove redundant <code>spl_autoload_register</code></td><td><a href="./reports/theme-only-audit-2/01-conventions-and-structure.html#autoloading">01 ARCH-01</a></td><td>0.1d</td></tr><tr><td>Replace <code>is_plugin_active()</code> with <code>class_exists</code> / <code>defined</code></td><td><a href="./reports/theme-only-audit-2/01-conventions-and-structure.html">01 ARCH-03</a></td><td>0.1d</td></tr><tr><td>Fix <code>404.php</code> placeholder content</td><td><a href="./reports/theme-only-audit-2/01-conventions-and-structure.html#template-hierarchy">01 TPL-02</a></td><td>0.5d</td></tr><tr><td>Fix <code>&lt;h1&gt;</code> missing <code>&lt;/h1&gt;</code> in search.php</td><td><a href="./reports/theme-only-audit-2/01-conventions-and-structure.html#template-hierarchy">01 TPL-03</a></td><td>0.1d</td></tr><tr><td>Decide: keep or delete <code>templates/default.php</code></td><td><a href="./reports/theme-only-audit-2/01-conventions-and-structure.html#template-hierarchy">01 TPL-04</a></td><td>0.25d</td></tr><tr><td><code>style.css</code> — add required header fields</td><td><a href="./reports/theme-only-audit-2/01-conventions-and-structure.html#stylecss-and-themejson-contracts">01 STYLE-01</a></td><td>0.25d</td></tr><tr><td>Unify identity across <code>style.css</code>, <code>composer.json</code>, <code>package.json</code>, webpack defaults</td><td><a href="./reports/theme-only-audit-2/01-conventions-and-structure.html#naming-and-identity">01 ID-01</a></td><td>0.5d</td></tr><tr><td>Fix PHPCS target to 8.1</td><td><a href="./reports/theme-only-audit-2/01-conventions-and-structure.html#coding-standards-php">01 PHP-01</a></td><td>0.25d</td></tr><tr><td>Adopt WordPress-Extra PHPCS ruleset + baseline</td><td><a href="./reports/theme-only-audit-2/01-conventions-and-structure.html#coding-standards-php">01 PHP-02</a></td><td>2d (initial baseline creation + trivial-fix pass)</td></tr><tr><td>Rewrite <code>Render::partial()</code> — fix <code>wp_cache_set</code> args + <code>call_user_method</code> + <code>extract</code></td><td><a href="./reports/theme-only-audit-2/02-non-native-apis.html#renderpartial-bugs">02 RENDER-01</a></td><td>1.5d</td></tr><tr><td>Rewrite <code>Helpers::generateLink()</code> with structured attribute building</td><td><a href="./reports/theme-only-audit-2/04-security.html#helpersgeneratelink-string-concatenation">04 SEC-GENERATELINK-01</a></td><td>0.5d</td></tr><tr><td>Fix <code>SVG::get()</code> — memoise, sanitise, validate path, use <code>href</code></td><td><a href="./reports/theme-only-audit-2/02-non-native-apis.html#svgget-and-svgicon">02 SVG-01</a></td><td>0.5d</td></tr><tr><td>Template escaping pass over every <code>template.php</code></td><td><a href="./reports/theme-only-audit-2/04-security.html#template-output-escaping">04 SEC-ESCAPE-01</a></td><td>5d (40 templates)</td></tr><tr><td>Add nonce verification to Ajax handler</td><td><a href="./reports/theme-only-audit-2/04-security.html#ajax-without-nonce-verification">04 SEC-AJAX-01</a></td><td>0.25d</td></tr><tr><td>Fix GTM ID validation + escaping</td><td><a href="./reports/theme-only-audit-2/04-security.html#gtm-injection">04 SEC-GTM-01</a></td><td>0.25d</td></tr><tr><td>Move CPT registration from constructors to <code>init</code> hook</td><td><a href="./reports/theme-only-audit-2/02-non-native-apis.html#jjgraingerposttypes">02 CPT-01</a></td><td>0.5d</td></tr><tr><td>Replace <code>jjgrainger/posttypes</code> with native <code>register_post_type</code></td><td><a href="./reports/theme-only-audit-2/02-non-native-apis.html#jjgraingerposttypes">02 POSTTYPES-01</a></td><td>0.5d</td></tr><tr><td>Fix menu walker — use <code>nav_menu_link_attributes</code> instead of <code>str_replace</code></td><td><a href="./reports/theme-only-audit-2/04-security.html#menu-walker-and-mega-menu-html-injection">04 SEC-MENU-01</a></td><td>0.5d</td></tr><tr><td>Fix share URL construction — <code>add_query_arg</code> + HTTPS</td><td><a href="./reports/theme-only-audit-2/04-security.html#social-sharing-url-construction">04 SEC-SOCIAL-01</a></td><td>0.25d</td></tr><tr><td>Remove dead <code>start_operation</code> / <code>end_operation</code> hooks</td><td><a href="./reports/theme-only-audit-2/02-non-native-apis.html#custom-ops-hooks">02 OPS-01</a></td><td>0.1d</td></tr><tr><td>Remove unused <code>jeroendesloovere/vcard</code></td><td><a href="./reports/theme-only-audit-2/05-dependencies.html#composer-dependencies-theme">05 DEPS-VCARD-01</a></td><td>0.1d</td></tr><tr><td>Replace service-locator in <code>functions.php</code> with hooked bootstrap</td><td><a href="./reports/theme-only-audit-2/01-conventions-and-structure.html#autoloading">01 ARCH-02</a></td><td>1d</td></tr></tbody></table><p><strong>Total</strong>: ~14.5 days.</p><p><strong>Exit criteria</strong>: All P1 non-migration findings closed. <code>phpcs</code> baseline committed. Theme boots cleanly on PHP 8.1 with WordPress-Extra ruleset.</p><p><strong>Can ship independently</strong>: Yes, in weekly small batches. Each task is independently reviewable.</p><h2 id="phase-2-—-performance-wins-independent-of-migration" tabindex="-1">Phase 2 — Performance wins independent of migration <a class="header-anchor" href="#phase-2-—-performance-wins-independent-of-migration" aria-label="Permalink to &quot;Phase 2 — Performance wins independent of migration&quot;">​</a></h2><p><strong>Goal</strong>: Drop obvious perf issues without changing the content model.</p><table tabindex="0"><thead><tr><th>Task</th><th>Ref</th><th>Effort</th></tr></thead><tbody><tr><td>Replace <code>filemtime()</code> with webpack-manifest-driven versioning</td><td><a href="./reports/theme-only-audit-2/03-performance.html#asset-versioning-filemtime-vs-manifest">03 ASSET-VER-01</a></td><td>1d</td></tr><tr><td>Standardise <code>wp_register_script</code> strategies</td><td><a href="./reports/theme-only-audit-2/03-performance.html#enqueue-strategies">03 ENQUEUE-01</a></td><td>0.5d</td></tr><tr><td>Declare explicit script dependencies per block</td><td><a href="./reports/theme-only-audit-2/03-performance.html#enqueue-strategies">03 ENQUEUE-02</a></td><td>0.5d</td></tr><tr><td>Remove preload/onload CSS pattern; replace with <code>wp_style_add_data(..., &#39;path&#39;, ...)</code></td><td><a href="./reports/theme-only-audit-2/03-performance.html#the-preload--onload-css-pattern">03 PERF-PRELOAD-01</a></td><td>0.5d</td></tr><tr><td>Scope admin Swiper enqueue to block-editor screens</td><td><a href="./reports/theme-only-audit-2/03-performance.html#swiper-loading">03 PERF-SWIPER-ADMIN-01</a></td><td>0.1d</td></tr><tr><td>Delete hand-rolled speculation-rules tag</td><td><a href="./reports/theme-only-audit-2/03-performance.html#speculation-rules">03 PERF-SPEC-01</a></td><td>0.1d</td></tr><tr><td><code>theme.json</code> decision — commit or delete</td><td><a href="./reports/theme-only-audit-2/03-performance.html#themejson-disabled-on-the-front-end">03 PERF-THEME-JSON-01</a></td><td>2d</td></tr><tr><td>Add <code>composer audit</code> + <code>pnpm audit</code> to CI</td><td><a href="./reports/theme-only-audit-2/05-dependencies.html#upgrade-hygiene">05 DEPS-AUDIT-01</a></td><td>0.25d</td></tr><tr><td>Cache <code>Cards::queryPosts</code> + clean up Person meta_query</td><td><a href="./reports/theme-only-audit-2/03-performance.html#database-queries">03 PERF-QUERY-01, 02</a></td><td>1d</td></tr><tr><td>Caps-added options — remove from autoload</td><td><a href="./reports/theme-only-audit-2/03-performance.html#capability-writes-on-every-request">03 PERF-CAPS-02</a></td><td>0.25d</td></tr><tr><td>Preload variable fonts + font-display: swap</td><td><a href="./reports/theme-only-audit-2/03-performance.html#font-loading">03 PERF-FONT-01</a></td><td>0.5d</td></tr><tr><td>Subset fonts to script(s) used</td><td><a href="./reports/theme-only-audit-2/03-performance.html#font-loading">03 PERF-FONT-02</a></td><td>0.25d</td></tr></tbody></table><p><strong>Total</strong>: ~7 days.</p><p><strong>Exit criteria</strong>: Measurable improvement in Lighthouse / CrUX / RUM data. Target: 100–300ms LCP improvement on representative content pages.</p><p><strong>Can ship independently</strong>: Yes. Small-scope changes, easy to test.</p><h2 id="phase-2-5-—-hookability-pass" tabindex="-1">Phase 2.5 — Hookability pass <a class="header-anchor" href="#phase-2-5-—-hookability-pass" aria-label="Permalink to &quot;Phase 2.5 — Hookability pass&quot;">​</a></h2><p><strong>Goal</strong>: Add the <a href="./reports/theme-only-audit-2/07-reusability-and-plugin-extraction.html#proposed-hook-surface">proposed hook surface</a> to the current codebase. No behaviour changes — purely additive. Preconditions for Phase 7 (plugin extraction).</p><table tabindex="0"><thead><tr><th>Task</th><th>Effort</th></tr></thead><tbody><tr><td>Add <code>edwp/setup/*</code> hooks to <code>Setup.php</code></td><td>0.5d</td></tr><tr><td>Add <code>edwp/enqueue/*</code> hooks to <code>Setup.php</code> / <code>Admin.php</code></td><td>0.5d</td></tr><tr><td>Add <code>edwp/setting/{key}</code> wrapper around every <code>get_field(..., &#39;option&#39;)</code> call</td><td>1d</td></tr><tr><td>Add <code>edwp/modal/*</code> hooks to <code>Modals.php</code> (rename existing <code>edwp_*</code> to <code>edwp/*</code>)</td><td>0.5d</td></tr><tr><td>Add <code>edwp/nav/*</code> hooks to <code>Filters.php</code></td><td>0.5d</td></tr><tr><td>Add <code>edwp/media/*</code> hooks to <code>Media.php</code></td><td>0.25d</td></tr><tr><td>Add <code>edwp/scripts/*</code> hooks to site-scripts pipeline</td><td>0.5d</td></tr><tr><td>Add <code>edwp/template/*</code> hooks to <code>Render::partial</code> or new loader</td><td>0.5d</td></tr><tr><td>Register <code>edwp/setting</code> Block Bindings source</td><td>0.5d</td></tr><tr><td>Write hook-reference documentation (<code>docs/hooks.md</code>)</td><td>1d</td></tr></tbody></table><p><strong>Total</strong>: ~5.75 days.</p><p><strong>Exit criteria</strong>: Every custom hook documented with <code>@since</code>, <code>@param</code>, usage example. Block Bindings source registered and tested from a pattern. No behaviour regressions.</p><p><strong>Can ship independently</strong>: Yes. Purely additive.</p><h2 id="phase-3-—-block-kit-and-representative-native-block" tabindex="-1">Phase 3 — Block-kit and representative native block <a class="header-anchor" href="#phase-3-—-block-kit-and-representative-native-block" aria-label="Permalink to &quot;Phase 3 — Block-kit and representative native block&quot;">​</a></h2><p><strong>Goal</strong>: Build the <code>edwp/wp-block-kit</code> Composer library and prove the native-block pattern with <strong>one representative migration</strong>.</p><table tabindex="0"><thead><tr><th>Task</th><th>Effort</th></tr></thead><tbody><tr><td>Build <code>edwp/wp-block-kit</code> package (class + hooks + tests)</td><td>3d</td></tr><tr><td>Publish to internal GitHub + tag v1.0.0</td><td>0.5d</td></tr><tr><td>Set up <code>@wordpress/scripts</code> alongside existing webpack</td><td>1d</td></tr><tr><td>Migrate one block end-to-end as a reference</td><td>3d</td></tr><tr><td>Write migration runbook (step-by-step for each future block)</td><td>1d</td></tr></tbody></table><p><strong>Recommended reference block</strong>: <code>acf/accordion</code>. It has:</p><ul><li>Non-trivial interactivity (close-all, open-first, chevron icon).</li><li>Repeater field (heading + WYSIWYG).</li><li>Moderate JS (replaceable with <code>core/details</code> + Interactivity API).</li><li>Low template complexity.</li></ul><p>If migration works smoothly for Accordion, the pattern generalises. If it doesn&#39;t, uncover the gaps before committing to migrating 26 more.</p><p><strong>Total</strong>: ~8.5 days.</p><p><strong>Exit criteria</strong>: One native block shipped. Migration runbook documented. <code>@wordpress/scripts</code> build running in CI.</p><h2 id="phase-4-—-block-by-block-migration" tabindex="-1">Phase 4 — Block-by-block migration <a class="header-anchor" href="#phase-4-—-block-by-block-migration" aria-label="Permalink to &quot;Phase 4 — Block-by-block migration&quot;">​</a></h2><p><strong>Goal</strong>: Migrate the remaining 26 blocks and 11 components to native.</p><p>Order by <strong>user value × complexity</strong>, roughly:</p><p><strong>Batch 1: Simplest blocks with direct native equivalents (2d each)</strong></p><ul><li><code>acf/separator</code> → <code>core/separator</code> (delete block, theme styling only)</li><li><code>acf/shortcode</code> → <code>core/shortcode</code> (delete block)</li><li><code>acf/buttons</code> → <code>core/buttons</code> (delete block; keep <code>Button</code> component style variation)</li><li><code>acf/content</code> → block pattern + core blocks (delete block)</li></ul><p>Sub-total: ~8d for 4 blocks.</p><p><strong>Batch 2: Layout primitives (3d each — heavy stylistic work)</strong></p><ul><li><code>acf/column</code> → <code>core/column</code></li><li><code>acf/group</code> → <code>core/group</code></li></ul><p>Sub-total: ~6d. Highest code savings (these are the largest blocks).</p><p><strong>Batch 3: Interactive blocks (3–5d each)</strong></p><ul><li><code>acf/accordion</code> → already done in Phase 3.</li><li><code>acf/tabbed-content</code> → custom block + Interactivity API.</li><li><code>acf/gallery</code> → <code>core/gallery</code> + custom modal-zoom extension.</li><li><code>acf/video</code> → <code>core/video</code> / <code>core/embed</code> with custom preview.</li></ul><p>Sub-total: ~12d.</p><p><strong>Batch 4: Content / query blocks (3d each)</strong></p><ul><li><code>acf/cards</code> → split into <code>edwp/cards</code> + <code>edwp/query-cards</code>.</li><li><code>acf/authors</code> → <code>core/query</code> + custom <code>edwp/author</code> component.</li><li><code>acf/post-meta</code> → core <code>core/post-*</code> blocks + custom <code>edwp/read-time</code>.</li><li><code>acf/testimonials-block</code> → <code>edwp/testimonial</code> + patterns.</li><li><code>acf/stats</code> → <code>edwp/stat</code> component + columns.</li></ul><p>Sub-total: ~15d.</p><p><strong>Batch 5: Domain-specific blocks (2–3d each)</strong></p><ul><li><code>acf/breadcrumbs</code> → custom native block (keeps existing logic, drops RM).</li><li><code>acf/contact-details</code> → custom native block.</li><li><code>acf/form-block</code> / <code>acf/newsletter-signup</code> → consolidated into one form-embed block.</li><li><code>acf/map</code> → custom native block with Google Maps.</li><li><code>acf/menu</code> → <code>core/navigation</code> + patterns.</li><li><code>acf/socials</code> → <code>core/social-links</code> + custom sharing block.</li><li><code>acf/logos</code> → custom block with CSS scroll-snap.</li><li><code>acf/image</code> → custom block (for multi-breakpoint sources).</li><li><code>acf/global-block</code> → replaced by core synced patterns.</li><li><code>acf/style-config</code> → finish or delete.</li></ul><p>Sub-total: ~22d.</p><p><strong>Components</strong> (done as needed alongside blocks that use them):</p><ul><li>Button, Card, CardPerson, Heading, Paragraph, Author, Stat, Tag, Testimonial, Toggle — most are replaced by core blocks or small <code>edwp/*</code> components.</li></ul><p><strong>Total Phase 4</strong>: ~65 days + QA. This is the single largest item in the roadmap.</p><p><strong>Exit criteria</strong>: All blocks and components running on native WordPress. Tests updated. Visual regression suite green against a reference site snapshot.</p><h2 id="phase-5-—-acf-removal-data-migration" tabindex="-1">Phase 5 — ACF removal + data migration <a class="header-anchor" href="#phase-5-—-acf-removal-data-migration" aria-label="Permalink to &quot;Phase 5 — ACF removal + data migration&quot;">​</a></h2><p><strong>Goal</strong>: Remove ACF Pro. Cannot happen before Phase 4 completes.</p><table tabindex="0"><thead><tr><th>Task</th><th>Effort</th></tr></thead><tbody><tr><td>Write WP-CLI migration command: parse <code>post_content</code>, convert <code>acf/*</code> block markers to native block markers</td><td>5d</td></tr><tr><td>Write WP-CLI migration command for theme options → <code>register_setting</code> values</td><td>2d</td></tr><tr><td>Write WP-CLI migration command for CPT meta → <code>register_post_meta</code> values</td><td>2d</td></tr><tr><td>Per-site data migration execution + QA</td><td>2d × number of live sites</td></tr><tr><td>Remove ACF Pro from composer.json</td><td>0.1d</td></tr><tr><td>Remove <code>stoutlogic/acf-builder</code></td><td>(included above)</td></tr><tr><td>Delete <code>inc/ACF.php</code>, <code>inc/ACF/Post.php</code>, <code>inc/ACF/ThemeOptions.php</code>, <code>inc/Globals/FieldGroups.php</code></td><td>0.5d</td></tr><tr><td>Delete <code>inc/WPML.php</code> (becomes obsolete)</td><td>0.1d</td></tr><tr><td>Delete <code>inc/RankMath.php</code> excerpt-fix (becomes obsolete)</td><td>0.1d</td></tr><tr><td>Scrub all <code>get_field()</code> / <code>get_fields()</code> calls — replace with native equivalents</td><td>2d</td></tr><tr><td>Scrub all <code>acf_*</code> function calls</td><td>1d</td></tr></tbody></table><p><strong>Total (one site)</strong>: ~12.5 days + 2d per live site for the migration itself.</p><p><strong>Exit criteria</strong>: ACF Pro uninstalled from at least one live site without data loss. Site renders identically to pre-migration.</p><h2 id="phase-6-—-dependency-removals" tabindex="-1">Phase 6 — Dependency removals <a class="header-anchor" href="#phase-6-—-dependency-removals" aria-label="Permalink to &quot;Phase 6 — Dependency removals&quot;">​</a></h2><p><strong>Goal</strong>: Remove Rank Math, WPMDB Pro, and make Gravity Forms / WPML optional.</p><table tabindex="0"><thead><tr><th>Task</th><th>Ref</th><th>Effort</th></tr></thead><tbody><tr><td>Write in-theme SEO module (meta tags, JSON-LD schema, robots, sitemap)</td><td><a href="./reports/theme-only-audit-2/02-non-native-apis.html#rank-math-dependencies">02 RANKMATH-01</a></td><td>3d</td></tr><tr><td>Per-site Rank Math → native SEO migration + QA</td><td>2d × live sites</td><td></td></tr><tr><td>Remove Rank Math from composer.json</td><td>0.1d</td><td></td></tr><tr><td>Install Redirection plugin (replaces Rank Math redirects)</td><td>0.1d</td><td></td></tr><tr><td>Migrate Rank Math redirects → Redirection plugin DB</td><td>0.5d</td><td></td></tr><tr><td>Remove WPMDB Pro from starter composer.json</td><td>0.1d</td><td></td></tr><tr><td>Document WP-CLI DB workflow in README</td><td>0.5d</td><td></td></tr><tr><td>Guard all Gravity Forms usages behind <code>class_exists(&#39;\\GFAPI&#39;)</code></td><td>1d</td><td></td></tr><tr><td>Remove Gravity Forms as hard dep in starter composer.json</td><td>0.1d</td><td></td></tr><tr><td>Guard all WPML usages behind <code>defined(&#39;ICL_SITEPRESS_VERSION&#39;)</code></td><td>0.5d</td><td></td></tr><tr><td>Remove WPML <code>is_plugin_active</code> hard-wire from <code>functions.php</code></td><td>0.1d</td><td></td></tr><tr><td>Consider Swiper → CSS scroll-snap or lazy-import per block</td><td><a href="./reports/theme-only-audit-2/02-non-native-apis.html#swiper">02 SWIPER-02</a></td><td>2d</td></tr><tr><td>Consider removing jQuery from FormBlock</td><td><a href="./reports/theme-only-audit-2/02-non-native-apis.html#jquery">02 JQUERY-01</a></td><td>0.25d</td></tr></tbody></table><p><strong>Total</strong>: ~10 days + 2d per live site for Rank Math migration.</p><p><strong>Exit criteria</strong>: Rank Math uninstalled. WPMDB Pro optional. Gravity Forms / WPML optional per project.</p><h2 id="phase-7-—-plugin-extraction" tabindex="-1">Phase 7 — Plugin extraction <a class="header-anchor" href="#phase-7-—-plugin-extraction" aria-label="Permalink to &quot;Phase 7 — Plugin extraction&quot;">​</a></h2><p><strong>Goal</strong>: Extract the reusable subsystems into standalone GitHub repos + Composer packages per <a href="./reports/theme-only-audit-2/07-reusability-and-plugin-extraction.html">07</a>.</p><h3 id="preconditions" tabindex="-1">Preconditions <a class="header-anchor" href="#preconditions" aria-label="Permalink to &quot;Preconditions&quot;">​</a></h3><p>Phase 7 uses Composer VCS as the distribution mechanism — the same general territory as <a href="https://roots.io/bedrock/" target="_blank" rel="noreferrer">Roots Bedrock</a>, which the team had prior difficulty with. Before Phase 7 begins, complete the DX investment tasks below. <strong>These are not optional.</strong> Without them, Phase 7 risks replaying whatever failure caused the Bedrock friction.</p><table tabindex="0"><thead><tr><th>Precondition task</th><th>Ref</th><th>Effort</th></tr></thead><tbody><tr><td>Run a Bedrock / Composer retrospective, capture findings in a 1-page doc</td><td><a href="./reports/theme-only-audit-2/07-reusability-and-plugin-extraction.html#dx-01--bedrock--composer-retrospective-precondition">07 DX-01</a></td><td>1d</td></tr><tr><td>Extend <code>setup/create.sh</code> to write Composer VCS entries + auth scaffolding</td><td><a href="./reports/theme-only-audit-2/07-reusability-and-plugin-extraction.html#dx-02--starter-setup-script-writes-composer-vcs-entries">07 DX-02</a></td><td>1d</td></tr><tr><td>Write <code>docs/COMPOSER-ONBOARDING.md</code> (first-time setup + top-10 errors)</td><td><a href="./reports/theme-only-audit-2/07-reusability-and-plugin-extraction.html#dx-03--composer-onboarding-documentation">07 DX-03</a></td><td>1d</td></tr><tr><td>Add Makefile shortcuts (<code>make edwp-add</code>, <code>edwp-update</code>, <code>edwp-status</code>)</td><td><a href="./reports/theme-only-audit-2/07-reusability-and-plugin-extraction.html#dx-04--makefile-shortcuts">07 DX-04</a></td><td>0.5d</td></tr><tr><td>Commit <code>.github/workflows/composer.yml</code> template</td><td><a href="./reports/theme-only-audit-2/07-reusability-and-plugin-extraction.html#dx-05--client-repo-ci-workflow-template">07 DX-05</a></td><td>1d</td></tr><tr><td>Budget for paired onboarding of the first developer per consuming project</td><td><a href="./reports/theme-only-audit-2/07-reusability-and-plugin-extraction.html#dx-06--paired-onboarding-for-the-first-consuming-project">07 DX-06</a></td><td>0.5d × per developer</td></tr></tbody></table><p><strong>Precondition total</strong>: ~4.5 engineer-days of DX investment before any extraction work begins.</p><h3 id="extraction-tasks" tabindex="-1">Extraction tasks <a class="header-anchor" href="#extraction-tasks" aria-label="Permalink to &quot;Extraction tasks&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Plugin / library</th><th>Effort</th><th>Ref</th></tr></thead><tbody><tr><td><code>edwp/wp-block-kit</code> library</td><td>3d</td><td>Already done in Phase 3</td></tr><tr><td><code>edwp/wp-theme-render</code> library</td><td>2d</td><td><a href="./reports/theme-only-audit-2/07-reusability-and-plugin-extraction.html#candidate-library-catalogue">07 REUSE-LIB-RENDER</a></td></tr><tr><td><code>edwp/wp-svg-sprite</code> library</td><td>2d</td><td><a href="./reports/theme-only-audit-2/07-reusability-and-plugin-extraction.html#candidate-library-catalogue">07 REUSE-LIB-SVG</a></td></tr><tr><td><code>edwp/wp-theme-utils</code> library</td><td>1d</td><td><a href="./reports/theme-only-audit-2/07-reusability-and-plugin-extraction.html#candidate-library-catalogue">07 REUSE-LIB-UTILS</a></td></tr><tr><td><code>edwp-core</code> MU plugin (media hardening + SVG)</td><td>3d</td><td><a href="./reports/theme-only-audit-2/07-reusability-and-plugin-extraction.html#candidate-plugin-catalogue">07 REUSE-EXTRACT-CORE</a></td></tr><tr><td><code>edwp-admin</code> plugin (login branding + widgets)</td><td>2d</td><td><a href="./reports/theme-only-audit-2/07-reusability-and-plugin-extraction.html#candidate-plugin-catalogue">07 REUSE-EXTRACT-ADMIN</a></td></tr><tr><td><code>edwp-site-options</code> plugin</td><td>5d</td><td><a href="./reports/theme-only-audit-2/07-reusability-and-plugin-extraction.html#candidate-plugin-catalogue">07 REUSE-EXTRACT-SITE-OPTIONS</a></td></tr><tr><td><code>edwp-modals</code> plugin</td><td>5d</td><td><a href="./reports/theme-only-audit-2/07-reusability-and-plugin-extraction.html#candidate-plugin-catalogue">07 REUSE-EXTRACT-MODALS</a></td></tr><tr><td><code>edwp-people</code> plugin</td><td>2d</td><td><a href="./reports/theme-only-audit-2/07-reusability-and-plugin-extraction.html#candidate-plugin-catalogue">07 REUSE-EXTRACT-PEOPLE</a></td></tr><tr><td><code>edwp-testimonials</code> plugin</td><td>2d</td><td><a href="./reports/theme-only-audit-2/07-reusability-and-plugin-extraction.html#candidate-plugin-catalogue">07 REUSE-EXTRACT-TESTIMONIALS</a></td></tr><tr><td><code>edwp-gravityforms-styling</code> plugin</td><td>1d</td><td><a href="./reports/theme-only-audit-2/07-reusability-and-plugin-extraction.html#candidate-plugin-catalogue">07 REUSE-EXTRACT-GF</a></td></tr><tr><td><code>edwp-classic-editor</code> plugin</td><td>1.5d</td><td><a href="./reports/theme-only-audit-2/07-reusability-and-plugin-extraction.html#candidate-plugin-catalogue">07 REUSE-EXTRACT-CLASSIC</a></td></tr><tr><td>Set up GitHub repos + Composer VCS config in starter</td><td>1d</td><td><a href="./reports/theme-only-audit-2/07-reusability-and-plugin-extraction.html#distribution-strategy">07 DIST-01</a></td></tr><tr><td>CI release automation per repo (version-from-tag)</td><td>1d per repo × ~10 repos</td><td><a href="./reports/theme-only-audit-2/07-reusability-and-plugin-extraction.html#distribution-strategy">07 DIST-02</a></td></tr><tr><td>Update theme to consume the extracted plugins</td><td>2d</td><td></td></tr></tbody></table><p><strong>Total</strong>: ~40 days (extraction work) + ~4.5 days (DX preconditions) = <strong>~44.5 days</strong>.</p><h3 id="decision-gate-before-entering-phase-7" tabindex="-1">Decision gate before entering Phase 7 <a class="header-anchor" href="#decision-gate-before-entering-phase-7" aria-label="Permalink to &quot;Decision gate before entering Phase 7&quot;">​</a></h3><p>Given the prior Bedrock friction, the team should have a <strong>go/no-go decision point</strong> after Phase 6 completes and the DX preconditions land. At that point:</p><ul><li>2–3 client sites are running the native-first architecture (Phases 3–5 complete).</li><li>The Composer surface has been shrunk by Phase 6 (Rank Math, WPMDB, ACF, acf-builder, jjgrainger/posttypes all gone).</li><li>The team&#39;s confidence with the leaner Composer setup is re-established.</li></ul><p>If after that the team is uncertain about adding ~10 Composer VCS packages, the correct posture is to <strong>defer Phase 7 indefinitely</strong> and continue running the starter as a clone-per-project template. The value of Phases 0–6 stands on its own. Phase 7 is an optimisation, not a requirement.</p><p><strong>Exit criteria</strong>: Starter template&#39;s <code>inc/</code> directory slimmed by ~50%. Each plugin independently taggable + consumable via Composer VCS. Hook-reference docs updated for each extracted surface.</p><h2 id="phase-8-—-parent-theme-evaluation-optional" tabindex="-1">Phase 8 — Parent-theme evaluation (optional) <a class="header-anchor" href="#phase-8-—-parent-theme-evaluation-optional" aria-label="Permalink to &quot;Phase 8 — Parent-theme evaluation (optional)&quot;">​</a></h2><p><strong>Goal</strong>: Evaluate whether the starter should become a parent theme (child themes per client) vs remaining a clone-per-project starter.</p><table tabindex="0"><thead><tr><th>Task</th><th>Effort</th></tr></thead><tbody><tr><td>Review outcomes from Phases 3–7 across 3+ client projects</td><td>2d</td></tr><tr><td>Prototype child-theme approach on one project</td><td>5d</td></tr><tr><td>Compare: maintenance burden vs fork-delta burden</td><td>1d</td></tr><tr><td>Decide and document</td><td>1d</td></tr></tbody></table><p><strong>Total</strong>: ~9 days.</p><p><strong>Recommendation</strong>: Defer until Phase 7 has landed across 3–5 live projects. Don&#39;t commit to parent-theme architecture until you have real evidence the upstream-change cadence would benefit from it.</p><h2 id="total-effort" tabindex="-1">Total effort <a class="header-anchor" href="#total-effort" aria-label="Permalink to &quot;Total effort&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Phase</th><th style="text-align:right;">Engineer-days</th><th style="text-align:right;">Calendar (1.5× buffer)</th></tr></thead><tbody><tr><td>0 — Security quick wins</td><td style="text-align:right;">2.25</td><td style="text-align:right;">~4 days</td></tr><tr><td>1 — Correctness + hygiene</td><td style="text-align:right;">14.5</td><td style="text-align:right;">~3 weeks</td></tr><tr><td>2 — Performance</td><td style="text-align:right;">7</td><td style="text-align:right;">~1.5 weeks</td></tr><tr><td>2.5 — Hookability</td><td style="text-align:right;">5.75</td><td style="text-align:right;">~1.5 weeks</td></tr><tr><td>3 — Block-kit + reference block</td><td style="text-align:right;">8.5</td><td style="text-align:right;">~2 weeks</td></tr><tr><td>4 — Block-by-block migration</td><td style="text-align:right;">65</td><td style="text-align:right;">~3 months</td></tr><tr><td>5 — ACF removal + data migration (per site)</td><td style="text-align:right;">12.5 + 2/site</td><td style="text-align:right;">+1 week per site</td></tr><tr><td>6 — Dependency removals</td><td style="text-align:right;">10 + 2/site</td><td style="text-align:right;">+~1 week per site</td></tr><tr><td>7 — Plugin extraction (incl. ~4.5d DX preconditions)</td><td style="text-align:right;">44.5</td><td style="text-align:right;">~2 months</td></tr><tr><td>8 — Parent-theme evaluation (optional)</td><td style="text-align:right;">9</td><td style="text-align:right;">~2 weeks</td></tr></tbody></table><p><strong>Grand total (one representative site, excluding Phase 8)</strong>: ~170 engineer-days ≈ <strong>8 months of one-developer calendar time</strong>, or roughly <strong>4 months with two developers</strong>.</p><p><strong>Phases 0–6 alone</strong> (security + correctness + performance + hookability + native migration + dependency removals) cover ~125 engineer-days / ~6 months single-developer calendar time. This is the <strong>minimum viable native-first migration</strong> and can land without any Phase 7 commitment. If the team never does Phase 7, Phases 0–6 still deliver the vast majority of the audit&#39;s value.</p><p><strong>For a starter template + 5 client sites</strong>: add ~20 days (4/site × 5) for Phases 5 and 6 data/config migration per site. Total ~185 engineer-days.</p><h2 id="dependencies-graph" tabindex="-1">Dependencies graph <a class="header-anchor" href="#dependencies-graph" aria-label="Permalink to &quot;Dependencies graph&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span> Phase 0 ──────────────────────────────┐</span></span>
<span class="line"><span>                                       │</span></span>
<span class="line"><span> Phase 1 ──────┬── Phase 2.5 ── Phase 3 ── Phase 4 ── Phase 5 ── Phase 6</span></span>
<span class="line"><span>              │                                                │</span></span>
<span class="line"><span>              └── Phase 2 ───────────────────────────────────────┘</span></span>
<span class="line"><span>                                                                │</span></span>
<span class="line"><span>                                                          Phase 7 ── Phase 8</span></span></code></pre></div><ul><li>Phase 0 is a hard blocker nobody should start Phase 1 without finishing.</li><li>Phase 1 and Phase 2 are parallel-compatible. Can be assigned to different developers.</li><li>Phase 2.5 requires Phase 1 (service-locator refactor creates the bootstrap seam for hook registration).</li><li>Phase 3 requires Phase 2.5 (block-kit consumes the hook surface).</li><li>Phase 4 requires Phase 3 (block-kit must exist before block migration).</li><li>Phase 5 (ACF removal) requires Phase 4 complete (can&#39;t remove ACF until all blocks are off it).</li><li>Phase 6 can run partially in parallel with Phase 5 but is cleanest after.</li><li>Phase 7 requires Phase 6 (extracted plugins shouldn&#39;t carry ACF / Rank Math dependencies).</li></ul><h2 id="recommended-order-of-client-rollout" tabindex="-1">Recommended order of client rollout <a class="header-anchor" href="#recommended-order-of-client-rollout" aria-label="Permalink to &quot;Recommended order of client rollout&quot;">​</a></h2><p>Rolling changes to live client sites:</p><ol><li><strong>Phase 0 + Phase 1 + Phase 2</strong>: roll out to all live sites immediately. Low-risk security and perf wins.</li><li><strong>Phase 2.5</strong>: roll to the starter template only. No live-site impact.</li><li><strong>Phase 3 + Phase 4 + Phase 5</strong>: roll to <strong>one pilot site</strong>. Use this site to validate the migration runbook. Keep for 4–8 weeks post-launch to catch any edge cases missed in QA.</li><li><strong>After pilot validates</strong>: schedule Phases 3–5 for each additional site, one at a time, on its own maintenance window. Budget ~1 week of calendar time per site.</li><li><strong>Phase 6</strong>: can happen alongside Phases 3–5, site-by-site, because it&#39;s independent.</li><li><strong>Phase 7</strong>: refactoring for internal engineering. No client-visible impact. Do it once the starter template has been through Phases 3–6 at least once.</li></ol><h2 id="risk-register" tabindex="-1">Risk register <a class="header-anchor" href="#risk-register" aria-label="Permalink to &quot;Risk register&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Risk</th><th>Likelihood</th><th>Impact</th><th>Mitigation</th></tr></thead><tbody><tr><td>ACF data migration loses content</td><td>Medium</td><td>High</td><td>Dry-run against a staging snapshot per site. Keep ACF installed as fallback during rollback window.</td></tr><tr><td>Third-party plugin incompatibility with native blocks</td><td>Medium</td><td>Medium</td><td>Smoke-test core + popular plugins against the migrated theme before cutover.</td></tr><tr><td>Gutenberg updates change APIs mid-migration</td><td>Low</td><td>Low</td><td>WP core BC promise is strong. Pin to a known WP version in composer for the duration.</td></tr><tr><td>Authoring UX regression (editors don&#39;t like native blocks vs ACF)</td><td>High</td><td>Medium</td><td>Run editor training sessions before cutover. Document the authoring changes. Expect short-term complaints.</td></tr><tr><td>Rank Math removal loses SEO data</td><td>Low</td><td>High</td><td>Export all meta tags / redirects before uninstall. Verify in SERP / crawl-report comparisons post-launch.</td></tr><tr><td>Swiper → CSS scroll-snap change degrades UX on some carousels</td><td>Low</td><td>Low</td><td>Fall back to Swiper lazy-import for edge cases.</td></tr><tr><td>Block-kit abstraction leaks: some blocks need escape hatches</td><td>Medium</td><td>Low</td><td>Design the base class with an <code>override_render()</code> hook for edge cases.</td></tr></tbody></table><p>Next: <a href="./reports/theme-only-audit-2/00-summary.html">00 — Summary</a></p>`,102)])])}const u=e(r,[["render",i]]);export{m as __pageData,u as default};
